ee:message.ee:set-payload:
%dw 2.0
output application/json


var validCondition = (item) -> item.qty > 0 and item.price > 0
var totalItemsCount = sizeOf(payload.items default [])


var validList = payload.items filter (item) -> validCondition(item)
var invalidList = payload.items filter (item) -> not validCondition(item)
---
{
    "processingStatus": "Processed",
    "customerMetrics": {
        "id": payload.customerId,
        "maskedPhone": "*******" ++ payload.phone[-3 to -1]
    },
    "audit": {
        "totalReceived": totalItemsCount,
        "totalValid": sizeOf(validList),
        "totalInvalid": sizeOf(invalidList),
        "requiresReview": sizeOf(invalidList) > 0
    },

    "validItems": validList map (item) -> {
        "partId": item.partId,
        "lineTotal": item.qty * item.price
    },
    "invalidItems": invalidList
}
